entity user_account {
    key tuid;
    mutable name;
    mutable login: text;
    key pubkey;
    index created_by: pubkey;
    role: text;
    mutable password_hash: text;
    mutable deleted: boolean;
    mutable aux_data: json;
}

            entity user_account {
                key tuid;
                mutable name;
                mutable login: text;
                key pubkey;
                index created_by: pubkey;
                role: text;
                mutable password_hash: text;
                mutable deleted: boolean;
                mutable aux_data: json;
            }

query q() { val search_role = ''; 
            val res = user_account @* {
                .role == search_role or search_role == '',
                .deleted == false
            } (
                .tuid,
                .name,
                .login,
                .role,
                .deleted,
                .aux_data
            );
            return res.size();
         }

